import{_ as t,c as a,o as i,ag as o}from"./chunks/framework.S-Qvb3wi.js";const b=JSON.parse('{"title":"Retention Labels","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-labels/index.md","filePath":"enterprise/retention-labels/index.md"}'),r={name:"enterprise/retention-labels/index.md"};function l(n,e,d,s,c,p){return i(),a("div",null,e[0]||(e[0]=[o('<h1 id="retention-labels" tabindex="-1">Retention Labels <a class="header-anchor" href="#retention-labels" aria-label="Permalink to &quot;Retention Labels&quot;">​</a></h1><p>The Retention Labels feature is an enterprise-grade capability that provides item-level retention overrides for archived emails. Unlike retention policies which apply rules to groups of emails, retention labels are manually or programmatically applied to individual emails to override the normal retention lifecycle with specific retention periods.</p><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><h3 id="_1-item-level-retention-override" tabindex="-1">1. Item-Level Retention Override <a class="header-anchor" href="#_1-item-level-retention-override" aria-label="Permalink to &quot;1. Item-Level Retention Override&quot;">​</a></h3><p>Retention labels represent a specific, targeted retention requirement that takes precedence over any automated retention policies. When an email has a retention label applied, the label&#39;s <code>retentionPeriodDays</code> becomes the governing retention period for that email, regardless of what any retention policy would otherwise specify.</p><h3 id="_2-one-label-per-email" tabindex="-1">2. One Label Per Email <a class="header-anchor" href="#_2-one-label-per-email" aria-label="Permalink to &quot;2. One Label Per Email&quot;">​</a></h3><p>Each archived email can have at most one retention label applied at any time. Applying a new label to an email automatically removes any existing label, ensuring a clean, unambiguous retention state.</p><h3 id="_3-deletion-behavior" tabindex="-1">3. Deletion Behavior <a class="header-anchor" href="#_3-deletion-behavior" aria-label="Permalink to &quot;3. Deletion Behavior&quot;">​</a></h3><p>Retention labels implement the following deletion logic:</p><ul><li><strong>Hard Delete</strong>: If a label has never been applied to any emails, it can be completely removed from the system.</li><li><strong>Soft Disable</strong>: If a label is currently applied to one or more emails, deletion attempts result in the label being marked as <code>isDisabled = true</code>. This keeps the label-email relations but the retention label won&#39;t take effective.</li><li><strong>Delete Disabled Labels</strong>: If a label is currently applied to one or more emails, and it is disabled, a deletion request will delete the label itself and all label-email relations (remove the label from emails it is tagged with).</li></ul><h3 id="_4-immutable-retention-period" tabindex="-1">4. Immutable Retention Period <a class="header-anchor" href="#_4-immutable-retention-period" aria-label="Permalink to &quot;4. Immutable Retention Period&quot;">​</a></h3><p>Once a retention label has been applied to any email, its <code>retentionPeriodDays</code> value becomes immutable to prevent tampering with active retention schedules. Labels can only have their retention period modified while they have zero applications.</p><h3 id="_5-user-attribution-and-audit-trail" tabindex="-1">5. User Attribution and Audit Trail <a class="header-anchor" href="#_5-user-attribution-and-audit-trail" aria-label="Permalink to &quot;5. User Attribution and Audit Trail&quot;">​</a></h3><p>Every label application and removal is attributed to a specific user and recorded in the <a href="./../audit-log/">Audit Log</a>. This includes both manual UI actions and automated API operations, ensuring complete traceability of retention decisions.</p><h3 id="_6-lifecycle-integration" tabindex="-1">6. Lifecycle Integration <a class="header-anchor" href="#_6-lifecycle-integration" aria-label="Permalink to &quot;6. Lifecycle Integration&quot;">​</a></h3><p>The <a href="./../retention-policy/lifecycle-worker.html">Lifecycle Worker</a> gives retention labels the highest priority during email evaluation. If an email has a retention label applied, the label&#39;s retention period is used instead of any matching retention policy rules.</p><h2 id="feature-requirements" tabindex="-1">Feature Requirements <a class="header-anchor" href="#feature-requirements" aria-label="Permalink to &quot;Feature Requirements&quot;">​</a></h2><p>The Retention Labels feature requires:</p><ul><li>An active <strong>Enterprise license</strong> with the <code>RETENTION_POLICY</code> feature enabled.</li><li>The <code>manage:all</code> permission for administrative operations (creating, editing, deleting labels).</li><li>The <code>delete:archive</code> permission for applying and removing labels from individual emails.</li></ul><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="legal-hold-alternative" tabindex="-1">Legal Hold Alternative <a class="header-anchor" href="#legal-hold-alternative" aria-label="Permalink to &quot;Legal Hold Alternative&quot;">​</a></h3><p>Retention labels can serve as a lightweight alternative to formal legal holds by applying extended retention periods (e.g., 10+ years) to specific emails related to litigation or investigation.</p><h3 id="executive-communications" tabindex="-1">Executive Communications <a class="header-anchor" href="#executive-communications" aria-label="Permalink to &quot;Executive Communications&quot;">​</a></h3><p>Apply extended retention to emails from or to executive leadership to ensure important business communications are preserved beyond normal retention periods.</p><h3 id="regulatory-exceptions" tabindex="-1">Regulatory Exceptions <a class="header-anchor" href="#regulatory-exceptions" aria-label="Permalink to &quot;Regulatory Exceptions&quot;">​</a></h3><p>Mark specific emails that must be retained for regulatory compliance (e.g., financial records, safety incidents) with appropriate retention periods regardless of general policy rules.</p><h3 id="project-specific-retention" tabindex="-1">Project-Specific Retention <a class="header-anchor" href="#project-specific-retention" aria-label="Permalink to &quot;Project-Specific Retention&quot;">​</a></h3><p>Apply custom retention periods to emails related to specific projects, contracts, or business initiatives that have unique preservation requirements.</p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The feature is composed of the following components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Location</th><th>Description</th></tr></thead><tbody><tr><td>Types</td><td><code>packages/types/src/retention.types.ts</code></td><td>Shared TypeScript types for labels and email label info.</td></tr><tr><td>Database Schema</td><td><code>packages/backend/src/database/schema/compliance.ts</code></td><td>Drizzle ORM table definitions for retention labels.</td></tr><tr><td>Label Service</td><td><code>packages/enterprise/src/modules/retention-policy/RetentionLabelService.ts</code></td><td>CRUD operations and label application logic.</td></tr><tr><td>API Controller</td><td><code>packages/enterprise/src/modules/retention-policy/retention-label.controller.ts</code></td><td>Express request handlers with Zod validation.</td></tr><tr><td>API Routes</td><td><code>packages/enterprise/src/modules/retention-policy/retention-policy.routes.ts</code></td><td>Route registration with auth and feature guards.</td></tr><tr><td>Frontend Page</td><td><code>packages/frontend/src/routes/dashboard/compliance/retention-labels/</code></td><td>SvelteKit page for label management.</td></tr><tr><td>Email Integration</td><td>Individual archived email pages</td><td>Label application UI in email detail views.</td></tr></tbody></table><h2 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h2><h3 id="retention-labels-table" tabindex="-1">Retention Labels Table <a class="header-anchor" href="#retention-labels-table" aria-label="Permalink to &quot;Retention Labels Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>uuid</code> (PK)</td><td>Auto-generated unique identifier.</td></tr><tr><td><code>name</code></td><td><code>varchar(255)</code></td><td>Human-readable label name (unique constraint).</td></tr><tr><td><code>retention_period_days</code></td><td><code>integer</code></td><td>Number of days to retain emails with this label.</td></tr><tr><td><code>description</code></td><td><code>text</code></td><td>Optional description of the label&#39;s purpose.</td></tr><tr><td><code>is_disabled</code></td><td><code>boolean</code></td><td>Whether the label is disabled (cannot be applied to new emails).</td></tr><tr><td><code>created_at</code></td><td><code>timestamptz</code></td><td>Creation timestamp.</td></tr></tbody></table><h3 id="email-label-applications-table" tabindex="-1">Email Label Applications Table <a class="header-anchor" href="#email-label-applications-table" aria-label="Permalink to &quot;Email Label Applications Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>email_id</code></td><td><code>uuid</code> (FK)</td><td>Reference to the archived email.</td></tr><tr><td><code>label_id</code></td><td><code>uuid</code> (FK)</td><td>Reference to the retention label.</td></tr><tr><td><code>applied_at</code></td><td><code>timestamptz</code></td><td>Timestamp when the label was applied.</td></tr><tr><td><code>applied_by_user_id</code></td><td><code>uuid</code> (FK)</td><td>User who applied the label (nullable for API key operations).</td></tr></tbody></table><p>The table uses a composite primary key of <code>(email_id, label_id)</code> to enforce the one-label-per-email constraint at the database level.</p><h2 id="integration-points" tabindex="-1">Integration Points <a class="header-anchor" href="#integration-points" aria-label="Permalink to &quot;Integration Points&quot;">​</a></h2><h3 id="lifecycle-worker" tabindex="-1">Lifecycle Worker <a class="header-anchor" href="#lifecycle-worker" aria-label="Permalink to &quot;Lifecycle Worker&quot;">​</a></h3><p>The lifecycle worker queries the <code>email_retention_labels</code> table during email evaluation. If an email has a retention label applied, the label&#39;s <code>retentionPeriodDays</code> takes precedence over any retention policy evaluation.</p><h3 id="audit-log" tabindex="-1">Audit Log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit Log&quot;">​</a></h3><p>All retention label operations generate audit log entries:</p><ul><li><strong>Label Creation</strong>: Action type <code>CREATE</code>, target type <code>RetentionLabel</code></li><li><strong>Label Updates</strong>: Action type <code>UPDATE</code>, target type <code>RetentionLabel</code></li><li><strong>Label Deletion/Disabling</strong>: Action type <code>DELETE</code> or <code>UPDATE</code>, target type <code>RetentionLabel</code></li><li><strong>Label Application</strong>: Action type <code>UPDATE</code>, target type <code>ArchivedEmail</code>, details include label information</li><li><strong>Label Removal</strong>: Action type <code>UPDATE</code>, target type <code>ArchivedEmail</code>, details include removed label information</li></ul><h3 id="email-detail-pages" tabindex="-1">Email Detail Pages <a class="header-anchor" href="#email-detail-pages" aria-label="Permalink to &quot;Email Detail Pages&quot;">​</a></h3><p>Individual archived email pages display any applied retention label and provide controls for users with appropriate permissions to apply or remove labels.</p>',45)]))}const m=t(r,[["render",l]]);export{b as __pageData,m as default};
